#define THREADS_PER_BLOCK 256
#define MAXBLOCKS 65536

#define __CL_ENABLE_EXCEPTIONS
#include "CLHelper.h"
typedef struct {
  float weight;
  long assign;  
  float cost;  
} Point_Struct;


float *work_mem_h = NULL;
float *coord_h = NULL;
float *gl_lower = NULL;
Point_Struct *p_h = NULL;


cl_mem work_mem_d;
cl_mem coord_d;
cl_mem  center_table_d;
cl_mem  switch_membership_d;
cl_mem p_d;

static int c = 0;			

void quit(char *message){
	printf("%s\n", message);
	exit(1);
}

void freeDevMem(){
	try{
		if(work_mem_d) _clFree(work_mem_d);
		if(center_table_d) _clFree(center_table_d);
		if(switch_membership_d) _clFree(switch_membership_d);
		if(p_d) _clFree(p_d);
		if(coord_d) _clFree(coord_d);

		if(work_mem_h) {
			_clFreeHost(1, work_mem_h);
			work_mem_h = NULL;
		}

		if(coord_h) {
			free(coord_h);
			coord_h = NULL;
		}
		if(gl_lower) {
			free(gl_lower);
			gl_lower = NULL;
		}
		if(p_h) {
			free(p_h);
			p_h = NULL;
		}
	}
	catch(string msg){
		quit(&(msg[0]));
	}	
}


void allocDevMem(int num, int dim, int kmax){
	try{
		int stride = kmax + 1;
		work_mem_d = _clMalloc(stride * num * sizeof(float));
		center_table_d = _clMalloc(num * sizeof(int));
		switch_membership_d = _clMalloc(num * sizeof(char));
		p_d = _clMalloc(num * sizeof(Point_Struct));
		coord_d = _clMalloc(num * dim * sizeof(float));
	}
	catch(string msg){
		quit(&(msg[0]));
	}	
}

float pgain( long x, Points *points, float z, long int *numcenters, int kmax, bool *is_center, int *center_table, char *switch_membership,
							double *serial, double *cpu_gpu_memcpy, double *memcpy_back, double *gpu_malloc, double *kernel){
	float gl_cost = 0;
	try{
#ifdef PROFILE_TMP
	double t1 = gettime();
#endif
	int K	= *numcenters ;						
	int num    =   points->num;				
	int dim     =   points->dim;				
	int stride = K + 1;

	int count = 0;
	for( int i=0; i<num; i++){
		if( is_center[i] )
			center_table[i] = count++;
	}

#ifdef PROFILE_TMP
	double t2 = gettime();
	*serial += t2 - t1;
#endif


	if( c == 0 ) {
#ifdef PROFILE_TMP
		double t3 = gettime();
#endif
	coord_h = (float*) malloc( num * dim * sizeof(float));								
	gl_lower = (float*) malloc( (K + 1) * sizeof(float) );
#ifdef  TIMING
	gettimeofday(&tv_mem_alloc_start, NULL);
#endif
	work_mem_h = (float*)_clMallocHost(stride * num * sizeof(float));
#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	p_h = (Point_Struct*)malloc(num*sizeof(Point_Struct));	



	for(int i=0; i<dim; i++){
		for(int j=0; j<num; j++)
			coord_h[ (num*i)+j ] = points->p[j].coord[i];
	}
#ifdef PROFILE_TMP		
	double t4 = gettime();
	*serial += t4 - t3;
#endif
#ifdef  TIMING
	gettimeofday(&tv_mem_alloc_start, NULL);
#endif

	allocDevMem(num, dim, kmax);
#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif
#ifdef PROFILE_TMP
	double t5 = gettime();
	*gpu_malloc += t5 - t4;
#endif


	_clMemcpyH2D(coord_d, coord_h, num*dim*sizeof(float));		
#ifdef PROFILE_TMP
	double t6 = gettime();
	*cpu_gpu_memcpy += t6 - t5;
#endif
	}	
#ifdef PROFILE_TMP
	double t100 = gettime();
#endif

	for(int i=0; i<num; i++){
		p_h[i].weight = ((points->p)[i]).weight;
		p_h[i].assign = ((points->p)[i]).assign;
		p_h[i].cost = ((points->p)[i]).cost;	
	}

#ifdef PROFILE_TMP
	double t101 = gettime();
	*serial += t101 - t100;
#endif
#ifdef PROFILE_TMP
	double t7 = gettime();
#endif


	_clMemcpyH2D(center_table_d,  center_table, num*sizeof(int));
	_clMemcpyH2D(p_d,  p_h,  num * sizeof(Point_Struct));
#ifdef PROFILE_TMP
	double t8 = gettime();
	*cpu_gpu_memcpy += t8 - t7;
#endif



	size_t smSize = dim * sizeof(float);
#ifdef PROFILE_TMP
	double t9 = gettime();
#endif
	_clMemset(switch_membership_d, 0, num*sizeof(char));
	_clMemset(work_mem_d, 0, stride * num * sizeof(float));

	int kernel_id = 0;
	int arg_idx = 0;		

	kernel_id = 1;
	arg_idx = 0;
	_clSetArgs(kernel_id, arg_idx++, p_d);
	_clSetArgs(kernel_id, arg_idx++, coord_d);
	_clSetArgs(kernel_id, arg_idx++, work_mem_d);
	_clSetArgs(kernel_id, arg_idx++, center_table_d);
	_clSetArgs(kernel_id, arg_idx++, switch_membership_d);
	_clSetArgs(kernel_id, arg_idx++, 0, smSize);
	_clSetArgs(kernel_id, arg_idx++, &num, sizeof(int));
	_clSetArgs(kernel_id, arg_idx++, &dim, sizeof(int));
	_clSetArgs(kernel_id, arg_idx++, &x, sizeof(long));
	_clSetArgs(kernel_id, arg_idx++, &K, sizeof(int));
	_clSetArgs(kernel_id, arg_idx++, &stride, sizeof(int));


	_clInvokeKernel(kernel_id, num, THREADS_PER_BLOCK); 
	_clFinish();

	#ifdef PROFILE_TMP
	double t10 = gettime();
	*kernel += t10 - t9;
#endif


	_clMemcpyD2H(switch_membership, switch_membership_d, num * sizeof(char));	
	_clMemcpyD2H(work_mem_h, work_mem_d, stride * num * sizeof(float));

#ifdef PROFILE_TMP
	double t11 = gettime();
	*memcpy_back += t11 - t10;
#endif


	int numclose = 0;
	gl_cost = z;


	for(int i=0; i < num; i++){	
		if( is_center[i] ) {
			float low = z;

		    for( int j = 0; j < num; j++ )
				low += work_mem_h[ j*stride + center_table[i] ];

		    gl_lower[center_table[i]] = low;

		    if ( low > 0 ) {
				numclose++;				
				work_mem_h[i*stride+K] -= low;
		    }
		}
		gl_cost += work_mem_h[i*stride+K];
	}



	if ( gl_cost < 0 ) {
		for(int i=0; i<num; i++){

			bool close_center = gl_lower[center_table[points->p[i].assign]] > 0 ;
		    if ( (switch_membership[i]=='1') || close_center ) {
				points->p[i].cost = points->p[i].weight * dist(points->p[i], points->p[x], points->dim);
				points->p[i].assign = x;
		    }
	    }

		for(int i=0; i<num; i++){
			if( is_center[i] && gl_lower[center_table[i]] > 0 )
				is_center[i] = false;
		}

		is_center[x] = true;
		*numcenters = *numcenters +1 - numclose;
	}
	else
		gl_cost = 0;  

#ifdef PROFILE_TMP
	double t12 = gettime();
	*serial += t12 - t11;
#endif
	c++;
	}
	catch(string msg){
		printf("--cambine:%s\n", msg.c_str());
		freeDevMem();
		_clRelease();
		exit(-1);		
	}
	catch(...){
		printf("--cambine: unknow reasons in pgain\n");
	}






	return -gl_cost;
}
